// Netstar Proxy — Cloudflare Worker
// Real endpoints discovered from original working code:
//   ubi-api.netstaraus.com.au  /vehicle/vehicles  (x-api-key auth)
//   fleetai-api.netstaraus.com.au  /external/drivers/driver-performance-summary  (x-api-key auth)
//   fleetai-api.netstaraus.com.au  /external/reports/object-status  (x-api-key auth)

const NETSTAR_BASE = "https://fleetai-api.netstaraus.com.au";
const UBI_BASE = "https://ubi-api.netstaraus.com.au";
const FALLBACK_KEY = "aROAW0rN00qS3Ar5iOnog";
const COMPANY = "Netstar Demo";
const LOCATION = "Netstar Demo";
const FTC_HTML = atob("");


function getKey(env) { return env.FLEETAI_API_KEY || FALLBACK_KEY; }

const CORS = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization, x-api-key",
};

function corsResponse(body, status = 200) {
  return new Response(body, { status, headers: { "Content-Type": "application/json", ...CORS } });
}
function errorResponse(msg, status = 500) {
  return corsResponse(JSON.stringify({ error: msg }), status);
}

// UBI API — vehicle list
async function ubiGET(path, env) {
  const res = await fetch(UBI_BASE + path, {
    method: "GET",
    headers: { "x-api-key": getKey(env), "Accept": "application/json" },
  });
  const text = await res.text();
  if (!res.ok) throw new Error("UBI " + res.status + ": " + text.slice(0, 200));
  return JSON.parse(text);
}

// FleetAI API — trip/driver performance data
async function netstarGET(path, env) {
  const res = await fetch(NETSTAR_BASE + path, {
    method: "GET",
    headers: { "x-api-key": getKey(env), "Accept": "application/json" },
  });
  const text = await res.text();
  if (!res.ok) throw new Error("FleetAI " + res.status + ": " + text.slice(0, 200));
  return JSON.parse(text);
}

// Get vehicle list from UBI API
async function getVehicleList(env) {
  const data = await ubiGET("/vehicle/vehicles", env);
  const list = Array.isArray(data) ? data : (data.data || []);
  return list.map(v => ({
    imei: String(v.Imei || v.imei || ""),
    id: String(v.Imei || v.imei || ""),
    registration: v.Registration || v.registration || v.Imei || "",
    make: v.Make || v.make || "—",
    model: v.Model || v.model || "—",
    year: v.Year || v.year || null,
    driver_name: v.DriverName || v.driver_name || v.Driver || "—",
    gvm_kg: parseFloat(v.GvmKg || v.gvm_kg || v.Gvm || 0) || 0,
    fuel_type: (v.FuelType || v.fuel_type || "diesel").toLowerCase(),
  }));
}

// Convert yyyy-MM-dd to dd-MM-yyyy HH:mm:ss as required by FleetAI API
function toFleetAIDate(isoDate, endOfDay = false) {
  const [y, m, d] = isoDate.split("-");
  return `${d}-${m}-${y} ${endOfDay ? "23:59:59" : "00:00:01"}`;
}

// Get driver performance — API enforces 10-day max window, so chunk and sum
// Simple approach: sum raw events and km across all chunks, score on event rate per 100km
async function getDriverPerf(dateFrom, dateTo, env) {
  const start = new Date(dateFrom);
  const end = new Date(dateTo);
  const chunks = [];

  let cursor = new Date(start);
  while (cursor <= end) {
    const chunkEnd = new Date(cursor);
    chunkEnd.setDate(chunkEnd.getDate() + 9);
    if (chunkEnd > end) chunkEnd.setTime(end.getTime());
    chunks.push({ from: cursor.toISOString().slice(0, 10), to: chunkEnd.toISOString().slice(0, 10) });
    cursor = new Date(chunkEnd);
    cursor.setDate(cursor.getDate() + 1);
  }

  // Fetch all chunks in parallel
  const chunkResults = await Promise.all(chunks.map(async chunk => {
    const q = new URLSearchParams({
      company_names: COMPANY,
      location_names: LOCATION,
      start_date_time: toFleetAIDate(chunk.from, false),
      end_date_time: toFleetAIDate(chunk.to, true),
    });
    try {
      const data = await netstarGET("/external/drivers/driver-performance-summary?" + q.toString(), env);
      return Array.isArray(data) ? data : (data.data || data.result || []);
    } catch(e) { return []; }
  }));

  // Sum raw events and km per driver across all chunks
  const merged = {};
  for (const rows of chunkResults) {
    for (const row of rows) {
      const key = String(row.driver_name || row.DriverName || "").trim();
      if (!key) continue;
      if (!merged[key]) {
        merged[key] = { ...row, _chunkCount: 1 };
      } else {
        merged[key]._chunkCount++;
        for (const f of ["total_running_km","harsh_breaking","harsh_acceleration","harsh_cornering","over_speed","night_drive","idling","non_stop_drive"]) {
          merged[key][f] = (parseFloat(merged[key][f]) || 0) + (parseFloat(row[f]) || 0);
        }
        // Keep highest max speed seen
        if ((parseFloat(row.max_speed) || 0) > (parseFloat(merged[key].max_speed) || 0)) {
          merged[key].max_speed = row.max_speed;
        }
        // Average the avg_speed
        merged[key].avg_speed = ((parseFloat(merged[key].avg_speed) || 0) * (merged[key]._chunkCount - 1) + (parseFloat(row.avg_speed) || 0)) / merged[key]._chunkCount;
        // Sum duration strings (just keep latest for display)
        merged[key].total_running_duration = row.total_running_duration || merged[key].total_running_duration;
      }
    }
  }

  // Convert to event rates per 100km for consistent scoring regardless of period length
  return Object.values(merged).map(r => {
    const km = parseFloat(r.total_running_km) || 0;
    if (km <= 0) return r;
    // Normalise event counts to per-100km rate, then scale to equivalent 500km period
    // This makes a 10-day and 60-day score directly comparable
    const norm = 500;
    return {
      ...r,
      total_running_km: km, // keep real km for display
      harsh_breaking:    Math.round((parseFloat(r.harsh_breaking) || 0) / km * norm),
      harsh_acceleration: Math.round((parseFloat(r.harsh_acceleration) || 0) / km * norm),
      harsh_cornering:   Math.round((parseFloat(r.harsh_cornering) || 0) / km * norm),
      over_speed:        Math.round((parseFloat(r.over_speed) || 0) / km * norm),
      night_drive:       Math.round((parseFloat(r.night_drive) || 0) / km * norm),
      idling:            Math.round((parseFloat(r.idling) || 0) / km * norm),
      avg_speed:         Math.round(parseFloat(r.avg_speed) || 0),
      _normalised: true,
      _norm_km: norm,
      _chunks: r._chunkCount,
    };
  });
}

// Get object status (odometer, fuel, speed) by IMEI
async function getObjectStatus(imei, env) {
  const data = await netstarGET("/external/reports/object-status?imei=" + imei, env);
  const list = Array.isArray(data) ? data : (data.data || []);
  return list.length > 0 ? list[0] : null;
}

// FTC summary — combines vehicles + trip data into one payload
async function ftcSummary(dateFrom, dateTo, env) {
  try {
    // Step 1: get vehicle list
    const vehicles = await getVehicleList(env);

    // Step 2: get driver performance for the period
    let driverPerf = [];
    try { driverPerf = await getDriverPerf(dateFrom, dateTo, env); } catch(e) {}

    // Step 3: enrich each vehicle with trip data and object status
    const enriched = await Promise.all(vehicles.map(async v => {
      // Get live object status FIRST — we need driver name from it for matching
      let status = null;
      if (v.imei) {
        try { status = await getObjectStatus(v.imei, env); } catch(e) {}
      }

      // Match driver perf by driver name — use status driver name as it's most reliable
      const statusDriver = String(status?.driver || v.driver_name || "").toLowerCase().trim();
      const perf = driverPerf.find(d => {
        const perfDriver = String(d.driver_name || d.DriverName || "").toLowerCase().trim();
        const perfReg = String(d.Registration || d.registration || "").toLowerCase();
        const vehReg = String(v.registration || "").toLowerCase();
        return (perfDriver && statusDriver && perfDriver === statusDriver) ||
               (perfReg && vehReg && perfReg === vehReg) ||
               String(d.Imei || d.imei || "") === v.imei;
      });

      // Real API fields from driver performance summary:
      // total_running_km, total_running_duration, avg_speed, max_speed, harsh_breaking etc.
      // No fuel field — estimate from km using typical diesel consumption
      const roadKm = parseFloat(perf?.total_running_km || perf?.DistanceKm || perf?.distance_km || perf?.Distance || 0);
      const offroadKm = parseFloat(perf?.OffRoadKm || perf?.off_road_km || 0);

      // Estimate fuel: diesel ~10L/100km for light vehicles, ~12L/100km for heavy
      // Use yesterday_odometer delta if available, otherwise estimate
      const estFuelPer100km = 11; // conservative fleet average
      const fuelLitres = parseFloat(perf?.FuelConsumed || perf?.fuel_consumed || perf?.Fuel || 0) ||
                         (roadKm + offroadKm > 0 ? ((roadKm + offroadKm) * estFuelPer100km / 100) : 0);

      const yesterdayOdom = parseFloat(status?.yesterday_odometer || 0);

      return {
        vehicle_id: v.id,
        registration: v.registration,
        make: v.make,
        model: v.model,
        year: v.year,
        gvm_kg: v.gvm_kg,
        fuel_type: v.fuel_type,
        driver: perf?.driver_name || perf?.DriverName || v.driver_name,
        odometer_start: parseFloat(perf?.OdometerStart || perf?.odometer_start || 0),
        odometer_end: parseFloat(perf?.OdometerEnd || perf?.odometer_end || yesterdayOdom || 0),
        fuel_litres: +fuelLitres.toFixed(1),
        road_km: roadKm,
        offroad_km: offroadKm,
        trips: parseInt(perf?.TripCount || perf?.trip_count || perf?.Trips || 0),
        fuel_estimated: fuelLitres > 0 && !(perf?.FuelConsumed || perf?.fuel_consumed),
        period: new Date(dateFrom).toLocaleDateString("en-AU", { month: "short", year: "numeric" }),
        source: "fleetai",
        _perf: perf,
        _status: status,
      };
    }));

    return corsResponse(JSON.stringify({
      source_endpoint: UBI_BASE + "/vehicle/vehicles",
      date_from: dateFrom,
      date_to: dateTo,
      driver_perf_count: driverPerf.length,
      driver_perf_names: driverPerf.map(d => d.driver_name || d.DriverName || "?"),
      vehicles: enriched,
    }), 200);

  } catch (e) {
    return errorResponse("FTC summary failed: " + e.message, 502);
  }
}

// Probe — tests all known real endpoints
async function probe(dateFrom, dateTo, env) {
  const key = getKey(env);
  const from = dateFrom || "2025-04-01";
  const to = dateTo || "2025-04-07";
  const xApiHeaders = { "x-api-key": key, "Accept": "application/json" };
  const bearerHeaders = { "Authorization": "Bearer " + key, "Accept": "application/json" };

  const candidates = [
    // Real UBI endpoints
    { url: UBI_BASE + "/vehicle/vehicles", headers: xApiHeaders },
    { url: UBI_BASE + "/vehicle/vehicles", headers: bearerHeaders },
    { url: UBI_BASE + "/driver/drivers", headers: xApiHeaders },
    // Real FleetAI endpoints
    { url: NETSTAR_BASE + "/external/drivers/driver-performance-summary?company_names=" + COMPANY + "&location_names=" + LOCATION + "&start_date_time=" + toFleetAIDate(from, false) + "&end_date_time=" + toFleetAIDate(to, true), headers: xApiHeaders },
    { url: NETSTAR_BASE + "/external/reports/object-status?imei=all", headers: xApiHeaders },
    { url: NETSTAR_BASE + "/external/reports/object-status", headers: xApiHeaders },
    // Fallback guesses
    { url: UBI_BASE + "/vehicles", headers: xApiHeaders },
    { url: UBI_BASE + "/api/vehicles", headers: xApiHeaders },
    { url: NETSTAR_BASE + "/external/vehicles", headers: xApiHeaders },
  ];

  const results = await Promise.allSettled(
    candidates.map(async ({ url, headers }) => {
      const res = await fetch(url, { headers });
      let preview = "";
      try { preview = (await res.text()).slice(0, 300); } catch {}
      return { url, auth: headers["x-api-key"] ? "x-api-key" : "bearer", status: res.status, ok: res.ok, preview };
    })
  );

  const report = results.map((r, i) =>
    r.status === "fulfilled" ? r.value : { ...candidates[i], status: "error", ok: false, preview: r.reason?.message }
  );

  return corsResponse(JSON.stringify({
    key_preview: key.slice(0,4) + "***" + key.slice(-4),
    summary: { accessible: report.filter(r => r.ok).length, denied: report.filter(r => r.status === 401 || r.status === 403).length },
    accessible: report.filter(r => r.ok),
    denied: report.filter(r => r.status === 401 || r.status === 403),
    other: report.filter(r => !r.ok && r.status !== 401 && r.status !== 403),
  }, null, 2));
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (request.method === "OPTIONS") return new Response(null, { status: 204, headers: CORS });

    if (path === "/health") {
      return corsResponse(JSON.stringify({ status: "ok", worker: "netstar-proxy", timestamp: new Date().toISOString(), key_preview: getKey(env).slice(0,4) + "***" }));
    }

    if (path === "/roi" || path === "/roi.html") {
      try {
        const res = await fetch("https://raw.githubusercontent.com/bs5jssxhm2-blip/Netstar-proxy/main/roi.html");
        const html = await res.text();
        return new Response(html, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
      } catch(e) { return new Response("Failed to fetch roi.html: " + e.message, { status: 502 }); }
    }

    if (path === "/driver" || path === "/driver.html") {
      try {
        const res = await fetch("https://raw.githubusercontent.com/bs5jssxhm2-blip/Netstar-proxy/main/driver.html");
        const html = await res.text();
        return new Response(html, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
      } catch(e) { return new Response("Failed to fetch driver.html: " + e.message, { status: 502 }); }
    }

    if (path === "/fleet-scores" || path === "/driver-score") {
      try {
        const annualKm = parseInt(url.searchParams.get("annual_km") || "15000");
        let dateFrom = url.searchParams.get("date_from") || url.searchParams.get("start_date") || (() => { const d = new Date(); d.setDate(d.getDate()-7); return d.toISOString().slice(0,10); })();
        const dateTo = url.searchParams.get("date_to") || url.searchParams.get("end_date") || (() => { const d = new Date(); d.setDate(d.getDate()-1); return d.toISOString().slice(0,10); })();
        const imeiFilter = url.searchParams.get("imei") || "";
        const driverFilter = (url.searchParams.get("driver") || url.searchParams.get("driver_name") || "").toLowerCase();

        // Step 1: get vehicle list
        let vlist = await getVehicleList(env);

        // Step 2: fetch ALL object statuses first, keyed by imei
        const osMap = {};
        await Promise.all(vlist.map(async v => {
          try { const os = await getObjectStatus(v.imei, env); if (os) osMap[v.imei] = os; } catch(e) {}
        }));

        // Step 3: enrich vehicle list with real driver names from object status
        vlist = vlist.map(v => Object.assign({}, v, {
          driver_name: osMap[v.imei]?.driver || v.driver_name || "Unknown",
          _matched: false,
        }));

        // For /driver-score with imei: resolve driver name from object status
        let resolvedDriverFilter = driverFilter;
        if (path === "/driver-score" && imeiFilter) {
          const os = osMap[imeiFilter];
          if (os?.driver) resolvedDriverFilter = os.driver.toLowerCase();
        }

        // Step 4: get driver performance — try requested range, fall back to shorter if no data
        // Cap at 60 days max since FleetAI retains ~60 days
        const maxDays = 60;
        const requestedDays = Math.round((new Date(dateTo) - new Date(dateFrom)) / 86400000);
        if (requestedDays > maxDays) {
          dateFrom = new Date(new Date(dateTo) - maxDays * 86400000).toISOString().slice(0, 10);
        }

        let list = await getDriverPerf(dateFrom, dateTo, env);

        // If no data, try progressively shorter recent windows
        if (!list.length) {
          for (const days of [30, 14, 7]) {
            const fb = new Date(new Date(dateTo) - days * 86400000).toISOString().slice(0, 10);
            list = await getDriverPerf(fb, dateTo, env);
            if (list.length) { dateFrom = fb; break; }
          }
        }

        if (!list.length) throw new Error("No driver data for this period. Try a date range within the last 30 days.");

        // Step 5: for each perf record, match to vehicle by driver name
        const scored = await Promise.all(list.map(async r => {
          const driverName = r.driver_name || r.driver || "Unknown";
          if (resolvedDriverFilter && resolvedDriverFilter !== driverName.toLowerCase()) return null;

          // Find matching vehicle by driver name
          let mv = null;
          for (let i = 0; i < vlist.length; i++) {
            if ((vlist[i].driver_name || "").toLowerCase() === driverName.toLowerCase() && !vlist[i]._matched) {
              mv = vlist[i]; vlist[i]._matched = true; break;
            }
          }
          // Fallback: first unmatched vehicle
          if (!mv) { for (let j = 0; j < vlist.length; j++) { if (!vlist[j]._matched) { mv = vlist[j]; vlist[j]._matched = true; break; } } }

          const imei = mv ? mv.imei : "";
          const os = osMap[imei] || {};

          // Speed penalty from actual max speed in trip data
          const maxSpd = parseInt(r.max_speed || 0);
          const speedPenalty = maxSpd > 130 ? 20 : maxSpd > 110 ? 10 : maxSpd > 100 ? 5 : 0;

          // Risk score calculation (matches original calcRisk logic)
          const harshBrake = parseInt(r.harsh_breaking || 0);
          const harshAccel = parseInt(r.harsh_acceleration || 0);
          const harshCorn = parseInt(r.harsh_cornering || 0);
          const avgSpd = parseInt(r.avg_speed || 0);
          const avgSpdPenalty = avgSpd > 80 ? 15 : avgSpd > 70 ? 10 : avgSpd > 60 ? 5 : 0;
          const eventScore = (harshBrake * 3) + (harshAccel * 3) + (harshCorn * 2);
          const rawScore = Math.min(100, eventScore + speedPenalty + avgSpdPenalty);
          const riskScore = isNaN(rawScore) ? 50 : Math.round(Math.min(Math.max(rawScore, 0), 100) * 10) / 10;
          const km = parseFloat(r.total_running_km || 0);
          const lc = isNaN(riskScore) ? 0 : Math.round(1200 * (Math.exp(riskScore / 35) - 0.9) * Math.sqrt((km || annualKm) / 15000));
          const rb = riskScore < 20 ? "Excellent" : riskScore < 40 ? "Good" : riskScore < 60 ? "Moderate" : riskScore < 80 ? "High" : "Very High";

          return {
            imei, driver_name: driverName,
            registration: mv?.registration || "", make: mv?.make || "", model: mv?.model || "",
            speed: os.speed || "0", location: os.location || "", status: os.status_hidden || "Unknown",
            risk_score: riskScore, loss_cost: lc, risk_band: rb,
            // Aliases for PAYD scorer renderDetail function
            predicted_loss_cost: lc,
            total_distance_km: km,
            km_driven: km, total_running_km: km,
            avg_speed: avgSpd, max_speed: maxSpd,
            total_running_duration: r.total_running_duration || "0:00",
            running_time: r.total_running_duration || "0:00",
            location_address: os.location || "",
            ignition: os.ignition_status || "Off",
            speed_live: os.speed || "0",
            period_from: dateFrom, period_to: dateTo,
            harsh_breaking: harshBrake, harsh_acceleration: harshAccel, harsh_cornering: harshCorn,
            non_stop_drive: parseInt(r.non_stop_drive || 0),
            night_drive: parseInt(r.night_drive || 0),
            over_speed: parseInt(r.over_speed || 0),
            idling: parseInt(r.idling || 0),
            features: { harsh_breaking: harshBrake, harsh_acceleration: harshAccel, harsh_cornering: harshCorn, max_speed: maxSpd, avg_speed: avgSpd, over_speed: parseInt(r.over_speed||0), night_drive: parseInt(r.night_drive||0), idling: parseInt(r.idling||0) },
          };
        }));

        const results = scored.filter(Boolean);
        if (path === "/driver-score") return corsResponse(JSON.stringify(results[0] || {}));
        return corsResponse(JSON.stringify({ vehicles: results, total: results.length, date_from: dateFrom, date_to: dateTo }));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/live-status") {
      try {
        const vlist = await getVehicleList(env);
        const statuses = await Promise.all(vlist.map(async v => {
          try { const os = await getObjectStatus(v.imei, env); return Object.assign({}, v, { driver_name: os?.driver || v.driver_name || "Unknown", speed: os?.speed || "0", location: os?.location || "", status: os?.status_hidden || "Unknown", coordinates: os?.coordinates || "" }); }
          catch(e) { return v; }
        }));
        return corsResponse(JSON.stringify({ vehicles: statuses, total: statuses.length, updated: new Date().toISOString() }));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/fleetai/probe") {
      return probe(url.searchParams.get("date_from"), url.searchParams.get("date_to"), env);
    }

    if (path === "/fleetai/ftc-summary") {
      const dateFrom = url.searchParams.get("date_from") || url.searchParams.get("from");
      const dateTo = url.searchParams.get("date_to") || url.searchParams.get("to");
      if (!dateFrom || !dateTo) return errorResponse("Missing date_from and date_to (YYYY-MM-DD)", 400);
      return ftcSummary(dateFrom, dateTo, env);
    }

    if (path === "/fleetai/vehicles") {
      try {
        const vehicles = await getVehicleList(env);
        return corsResponse(JSON.stringify({ vehicles, total: vehicles.length }));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/fleetai/trips") {
      const dateFrom = url.searchParams.get("date_from");
      const dateTo = url.searchParams.get("date_to");
      if (!dateFrom || !dateTo) return errorResponse("Missing date_from / date_to", 400);
      try {
        const data = await getDriverPerf(dateFrom, dateTo, env);
        return corsResponse(JSON.stringify(data));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/" || path === "/index.html") {
      const rawUrl = env.GITHUB_RAW_URL || "https://raw.githubusercontent.com/bs5jssxhm2-blip/Netstar-proxy/main/index.html";
      try {
        const res = await fetch(rawUrl);
        const html = await res.text();
        return new Response(html, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
      } catch(e) { return new Response("Failed to fetch: " + e.message, { status: 502 }); }
    }

    if (path === "/ftc" || path === "/ftc.html") {
      return new Response(FTC_HTML, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
    }

    if (path === "/ai-analysis" && request.method === "POST") {
      try {
        const { prompt } = await request.json();
        if (!prompt) return errorResponse("Missing prompt", 400);
        const res = await fetch("https://api.anthropic.com/v1/messages", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "x-api-key": env.ANTHROPIC_API_KEY || "",
            "anthropic-version": "2023-06-01",
          },
          body: JSON.stringify({ model: "claude-haiku-4-5-20251001", max_tokens: 800, messages: [{ role: "user", content: prompt }] }),
        });
        const data = await res.json();
        if (!res.ok) return errorResponse(data.error?.message || "Anthropic API error", res.status);
        const text = data.content?.filter(b => b.type === "text").map(b => b.text).join("") || "";
        return corsResponse(JSON.stringify({ text }));
      } catch(e) { return errorResponse(e.message, 500); }
    }

    return errorResponse("Unknown route: " + path, 404);
  },
};
